/**
 * мқҙлҜём§Җ м—…лЎңл“ң м»ҙнҸ¬л„ҢнҠё
 * 
 * кё°лҠҘ:
 * - нҢҢмқј м„ нғқ лҳҗлҠ” л“ңлһҳк·ё м•Ө л“ңлЎӯ
 * - мһҗлҸҷ м••м¶• (800KB мқҙн•ҳ)
 * - мқҙлҜём§Җ лҜёлҰ¬ліҙкё°
 * - R2 лҳҗлҠ” Base64 мһҗлҸҷ м„ нғқ
 */

import { useState, useRef } from 'react'
import { Upload, X, Loader2, ImageIcon } from 'lucide-react'
import imageCompression from 'browser-image-compression'
import api from '@/lib/api'

interface ImageUploadProps {
  value: string
  onChange: (url: string) => void
  label?: string
  maxSizeKB?: number
}

export default function ImageUpload({ 
  value, 
  onChange, 
  label = 'мқҙлҜём§Җ м—…лЎңл“ң',
  maxSizeKB = 800 
}: ImageUploadProps) {
  const [uploading, setUploading] = useState(false)
  const [error, setError] = useState('')
  const [dragActive, setDragActive] = useState(false)
  const [storageType, setStorageType] = useState<'r2' | 'base64' | null>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)

  async function handleFile(file: File) {
    setError('')
    setUploading(true)

    try {
      // нҢҢмқј нғҖмһ… кІҖмҰқ
      if (!file.type.startsWith('image/')) {
        throw new Error('мқҙлҜём§Җ нҢҢмқјл§Ң м—…лЎңл“ң к°ҖлҠҘн•©лӢҲлӢӨ.')
      }

      // нҢҢмқј нҒ¬кё° кІҖмҰқ (10MB мҙҲкіј мӢң кұ°л¶Җ)
      if (file.size > 10 * 1024 * 1024) {
        throw new Error('мқҙлҜём§Җ нҒ¬кё°лҠ” 10MB мқҙн•ҳм—¬м•ј н•©лӢҲлӢӨ.')
      }

      // мқҙлҜём§Җ м••м¶•
      const options = {
        maxSizeMB: maxSizeKB / 1024, // KBлҘј MBлЎң ліҖнҷҳ
        maxWidthOrHeight: 1920,
        useWebWorker: true,
        fileType: 'image/jpeg'
      }

      const compressedFile = await imageCompression(file, options)
      
      console.log('м••м¶• мҷ„лЈҢ:', {
        мӣҗліё: `${(file.size / 1024).toFixed(2)}KB`,
        м••м¶•: `${(compressedFile.size / 1024).toFixed(2)}KB`,
        м••м¶•лҘ : `${((1 - compressedFile.size / file.size) * 100).toFixed(1)}%`
      })

      // Base64лЎң ліҖнҷҳ
      const reader = new FileReader()
      reader.onload = async (e) => {
        const base64 = e.target?.result as string

        try {
          // API нҳём¶ңн•ҳм—¬ м—…лЎңл“ң
          const response = await api.post('/api/seller/upload-image', {
            image: base64,
            filename: file.name,
          })

          if (response.data.success) {
            onChange(response.data.url)
            setStorageType(response.data.storage)
            
            if (response.data.warning) {
              console.warn('[Image Upload]', response.data.warning)
            }
          } else {
            throw new Error(response.data.error || 'м—…лЎңл“ң мӢӨнҢЁ')
          }
        } catch (apiError: any) {
          console.error('API upload error:', apiError)
          throw new Error(apiError.response?.data?.error || apiError.message || 'м—…лЎңл“ң мӢӨнҢЁ')
        } finally {
          setUploading(false)
        }
      }
      reader.onerror = () => {
        throw new Error('нҢҢмқј мқҪкё°м—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.')
      }
      reader.readAsDataURL(compressedFile)

    } catch (err: any) {
      console.error('Image upload error:', err)
      setError(err.message || 'мқҙлҜём§Җ м—…лЎңл“ңм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.')
      setUploading(false)
    }
  }

  function handleFileSelect(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (file) handleFile(file)
  }

  function handleDrop(e: React.DragEvent) {
    e.preventDefault()
    setDragActive(false)
    const file = e.dataTransfer.files?.[0]
    if (file) handleFile(file)
  }

  function handleDragOver(e: React.DragEvent) {
    e.preventDefault()
    setDragActive(true)
  }

  function handleDragLeave() {
    setDragActive(false)
  }

  function handleRemove() {
    onChange('')
    if (fileInputRef.current) {
      fileInputRef.current.value = ''
    }
  }

  return (
    <div className="space-y-2">
      <label className="block text-sm font-medium text-gray-700">
        {label}
      </label>

      {/* м—…лЎңл“ң мҳҒм—ӯ */}
      {!value && (
        <div
          onDrop={handleDrop}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onClick={() => fileInputRef.current?.click()}
          className={`
            relative border-2 border-dashed rounded-lg p-8 text-center cursor-pointer
            transition-colors duration-200
            ${dragActive ? 'border-blue-500 bg-blue-50' : 'border-gray-300 hover:border-gray-400'}
            ${uploading ? 'pointer-events-none opacity-50' : ''}
          `}
        >
          <input
            ref={fileInputRef}
            type="file"
            accept="image/*"
            onChange={handleFileSelect}
            className="hidden"
            disabled={uploading}
          />

          {uploading ? (
            <div className="flex flex-col items-center gap-3">
              <Loader2 className="w-10 h-10 text-blue-500 animate-spin" />
              <p className="text-sm text-gray-600">мқҙлҜём§Җ м••м¶• мӨ‘...</p>
            </div>
          ) : (
            <div className="flex flex-col items-center gap-3">
              <Upload className="w-10 h-10 text-gray-400" />
              <div>
                <p className="text-sm font-medium text-gray-700">
                  нҒҙлҰӯн•ҳкұ°лӮҳ мқҙлҜём§ҖлҘј л“ңлһҳк·ён•ҳм„ёмҡ”
                </p>
                <p className="text-xs text-gray-500 mt-1">
                  JPG, PNG, GIF (мөңлҢҖ 10MB) вҖў мһҗлҸҷмңјлЎң {maxSizeKB}KB мқҙн•ҳлЎң м••м¶•лҗ©лӢҲлӢӨ
                </p>
              </div>
            </div>
          )}
        </div>
      )}

      {/* лҜёлҰ¬ліҙкё° */}
      {value && (
        <div className="relative">
          <div className="relative w-full h-48 bg-gray-100 rounded-lg overflow-hidden border">
            <img
              src={value}
              alt="м—…лЎңл“ңлҗң мқҙлҜём§Җ"
              className="w-full h-full object-contain"
              onError={(e) => {
                (e.target as HTMLImageElement).src = 'https://via.placeholder.com/400x300?text=Image+Error'
              }}
            />
            <button
              type="button"
              onClick={handleRemove}
              className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors"
            >
              <X className="w-4 h-4" />
            </button>
          </div>
          <p className="text-xs text-gray-500 mt-1 flex items-center gap-1">
            <ImageIcon className="w-3 h-3" />
            мқҙлҜём§Җк°Җ м—…лЎңл“ңлҗҳм—ҲмҠөлӢҲлӢӨ
            {storageType && (
              <span className="ml-1 px-1.5 py-0.5 bg-gray-100 rounded text-xs">
                {storageType === 'r2' ? 'вң… R2' : 'вҡ пёҸ Base64'}
              </span>
            )}
          </p>
        </div>
      )}

      {/* м—җлҹ¬ л©”мӢңм§Җ */}
      {error && (
        <div className="p-3 bg-red-50 border border-red-200 rounded-lg">
          <p className="text-sm text-red-700">{error}</p>
        </div>
      )}

      {/* R2 лҜёнҷңм„ұнҷ” кІҪкі  */}
      {storageType === 'base64' && (
        <div className="p-3 bg-yellow-50 border border-yellow-200 rounded-lg">
          <p className="text-xs text-yellow-800">
            вҡ пёҸ R2к°Җ нҷңм„ұнҷ”лҗҳм§Җ м•Ҡм•„ Base64 лӘЁл“ңлЎң м ҖмһҘлҗ©лӢҲлӢӨ. 
            R2 нҷңм„ұнҷ” к¶ҢмһҘ (м„ұлҠҘ н–ҘмғҒ, мҡ©лҹү м ңн•ң м—ҶмқҢ)
          </p>
        </div>
      )}

      {/* URL мһ…л Ҙ мҳөм…ҳ */}
      <details className="text-sm">
        <summary className="cursor-pointer text-gray-600 hover:text-gray-900">
          лҳҗлҠ” мқҙлҜём§Җ URL м§Ғм ‘ мһ…л Ҙ
        </summary>
        <div className="mt-2">
          <input
            type="url"
            value={value.startsWith('http') ? value : ''}
            onChange={(e) => onChange(e.target.value)}
            placeholder="https://example.com/image.jpg"
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
          />
          <p className="text-xs text-gray-500 mt-1">
            Unsplash, Pexels л“ұмқҳ мқҙлҜём§Җ URLмқ„ мһ…л Ҙн•  мҲҳ мһҲмҠөлӢҲлӢӨ
          </p>
        </div>
      </details>
    </div>
  )
}
