import { CustomModal, useModal } from '@/components/CustomModal'
import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import api from '@/lib/api'
import { useFirebaseStream } from '@/hooks/useFirebaseStream'
import { GripVertical } from 'lucide-react'

interface Product {
  id: number
  name: string
  price: number
  original_price: number
  discount_rate: number
  stock: number
  image_url: string
}

interface LiveStream {
  id: number
  title: string
  youtube_video_id: string
  status: string
  current_product_id: number | null
  created_at: string
  viewer_count?: number
}

export default function SellerLiveControlPage() {
  const navigate = useNavigate()
  const [streams, setStreams] = useState<LiveStream[]>([])
  const [products, setProducts] = useState<Product[]>([])
  const [selectedStream, setSelectedStream] = useState<LiveStream | null>(null)
  const [currentProductId, setCurrentProductId] = useState<number | null>(null)
  const [loading, setLoading] = useState(true)
  const [changing, setChanging] = useState(false)
  const [draggedIndex, setDraggedIndex] = useState<number | null>(null)
  const [viewerCounts, setViewerCounts] = useState<Record<number, number>>({})

  // рҹ”Ҙ Firebase мӢӨмӢңк°„ мҠӨнҠёлҰј кө¬лҸ… (м„ нғқлҗң мҠӨнҠёлҰј)
  const { streamData: firebaseStream } = useFirebaseStream(selectedStream?.id || null)

  // Firebaseм—җм„ң мғҒн’Ҳ ліҖкІҪ к°җм§Җ мӢң UI мһҗлҸҷ м—…лҚ°мқҙнҠё
  useEffect(() => {
    if (!firebaseStream || !selectedStream) return
    
    // мғҒн’Ҳмқҙ ліҖкІҪлҗҳм—Ҳмқ„ л•Ң currentProductId м—…лҚ°мқҙнҠё
    if (firebaseStream.current_product_id !== currentProductId) {
      setCurrentProductId(firebaseStream.current_product_id)
      console.log(`рҹ”Ҙ Firebase: Current product updated to ${firebaseStream.current_product_id}`)
    }
  }, [firebaseStream?.current_product_id, selectedStream?.id])

  useEffect(() => {
    // Check seller session (JWT-based)
    const accessToken = localStorage.getItem('access_token')
    const userType = localStorage.getItem('user_type')
    
    if (!accessToken || userType !== 'seller') {
      navigate('/seller/login')
      return
    }

    loadData()
  }, [navigate])

  // мӢӨмӢңк°„ мӢңмІӯмһҗ мҲҳ м—…лҚ°мқҙнҠё (10мҙҲл§ҲлӢӨ)
  useEffect(() => {
    if (streams.length === 0) return

    const fetchViewerCounts = async () => {
      try {
        const counts: Record<number, number> = {}
        for (const stream of streams) {
          const response = await api.get(`/api/streams/${stream.id}/viewer-count`)
          if (response.data.success) {
            counts[stream.id] = response.data.data.viewer_count
          }
        }
        setViewerCounts(counts)
      } catch (error) {
        console.error('[SellerLiveControl] Failed to fetch viewer counts:', error)
      }
    }

    // мҙҲкё° лЎңл“ң
    fetchViewerCounts()

    // 10мҙҲл§ҲлӢӨ м—…лҚ°мқҙнҠё
    const interval = setInterval(fetchViewerCounts, 10000)

    return () => clearInterval(interval)
  }, [streams])

  async function loadData() {
    try {
      // Load live streams
      const streamsRes = await api.get('/api/seller/streams')
      
      // Load products
      const productsRes = await api.get('/api/seller/products')

      const liveStreams = streamsRes.data.data.filter((s: LiveStream) => s.status === 'live')
      setStreams(liveStreams)
      setProducts(productsRes.data.data)

      // Auto-select first live stream
      if (liveStreams.length > 0) {
        setSelectedStream(liveStreams[0])
        setCurrentProductId(liveStreams[0].current_product_id)
      }

      setLoading(false)
    } catch (err) {
      console.error('Failed to load data:', err)
      setLoading(false)
    }
  }

  async function changeProduct(productId: number) {
    if (!selectedStream || changing) return

    setChanging(true)
    try {
      await api.post(
        `/api/seller/streams/${selectedStream.id}/change-product`,
        { productId }
      )

      setCurrentProductId(productId)
      alert('мғҒн’Ҳмқҙ ліҖкІҪлҗҳм—ҲмҠөлӢҲлӢӨ!')
    } catch (err: any) {
      alert(`мғҒн’Ҳ ліҖкІҪ мӢӨнҢЁ: ${err.response?.data?.error || err.message}`)
    } finally {
      setChanging(false)
    }
  }

  function handleDragStart(e: React.DragEvent, index: number) {
    setDraggedIndex(index)
    e.dataTransfer.effectAllowed = 'move'
  }

  function handleDragOver(e: React.DragEvent) {
    e.preventDefault()
    e.dataTransfer.dropEffect = 'move'
  }

  function handleDrop(e: React.DragEvent, dropIndex: number) {
    e.preventDefault()
    
    if (draggedIndex === null || draggedIndex === dropIndex) {
      setDraggedIndex(null)
      return
    }

    const newProducts = [...products]
    const [draggedProduct] = newProducts.splice(draggedIndex, 1)
    newProducts.splice(dropIndex, 0, draggedProduct)
    
    setProducts(newProducts)
    setDraggedIndex(null)
  }

  function handleDragEnd() {
    setDraggedIndex(null)
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600">лЎңл”© мӨ‘...</p>
        </div>
      </div>
    )
  }

  if (streams.length === 0) {
    return (
      <div className="min-h-screen bg-gray-50">
        <div className="max-w-7xl mx-auto px-4 py-8">
          <div className="bg-white rounded-lg shadow p-8 text-center">
            <h2 className="text-2xl font-bold text-gray-900 mb-4">м§„н–ү мӨ‘мқё лқјмқҙлёҢк°Җ м—ҶмҠөлӢҲлӢӨ</h2>
            <p className="text-gray-600 mb-6">лқјмқҙлёҢ л°©мҶЎмқ„ мӢңмһ‘н•ҳл Өл©ҙ лЁјм Җ лқјмқҙлёҢ мҠӨнҠёлҰјмқ„ мғқм„ұн•ҳм„ёмҡ”.</p>
            <button
              onClick={() => navigate('/seller')}
              className="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700"
            >
              лҢҖмӢңліҙл“ңлЎң лҸҢм•„к°Җкё°
            </button>
          </div>
        </div>
      </div>
    )
  }

  const currentProduct = products.find(p => p.id === currentProductId)

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Header */}
        <div className="mb-8">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h1 className="text-3xl font-bold text-gray-900">рҹ”ҙ лқјмқҙлёҢ мғҒн’Ҳ м»ЁнҠёлЎӨ</h1>
              {selectedStream && (
                <div className="flex items-center gap-2 mt-2 text-gray-600">
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                    <path d="M10 12a2 2 0 100-4 2 2 0 000 4z" />
                    <path fillRule="evenodd" d="M.458 10C1.732 5.943 5.522 3 10 3s8.268 2.943 9.542 7c-1.274 4.057-5.064 7-9.542 7S1.732 14.057.458 10zM14 10a4 4 0 11-8 0 4 4 0 018 0z" clipRule="evenodd" />
                  </svg>
                  <span className="font-semibold">{viewerCounts[selectedStream.id] || 0}лӘ… мӢңмІӯ мӨ‘</span>
                </div>
              )}
            </div>
            <button
              onClick={() => navigate('/seller')}
              className="text-gray-600 hover:text-gray-900"
            >
              лҢҖмӢңліҙл“ңлЎң лҸҢм•„к°Җкё°
            </button>
          </div>
          
          {/* Stream Selector */}
          {streams.length > 1 && (
            <select
              value={selectedStream?.id || ''}
              onChange={(e) => {
                const stream = streams.find(s => s.id === Number(e.target.value))
                setSelectedStream(stream || null)
                setCurrentProductId(stream?.current_product_id || null)
              }}
              className="w-full max-w-md px-4 py-2 border border-gray-300 rounded-lg"
            >
              {streams.map(stream => (
                <option key={stream.id} value={stream.id}>
                  {stream.title}
                </option>
              ))}
            </select>
          )}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Current Product Display */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-lg shadow p-6">
              <h2 className="text-xl font-bold text-gray-900 mb-4">нҳ„мһ¬ л…ём¶ң мӨ‘мқё мғҒн’Ҳ</h2>
              
              {currentProduct ? (
                <div className="border-2 border-blue-500 rounded-lg p-4">
                  <h3 className="font-bold text-lg mb-2">{currentProduct.name}</h3>
                  <div className="flex items-baseline gap-2 mb-2">
                    {currentProduct.discount_rate > 0 && (
                      <span className="text-red-500 font-bold">{currentProduct.discount_rate}%</span>
                    )}
                    <span className="text-xl font-bold">{currentProduct.price.toLocaleString()}мӣҗ</span>
                  </div>
                  {currentProduct.original_price > currentProduct.price && (
                    <p className="text-gray-500 line-through">{currentProduct.original_price.toLocaleString()}мӣҗ</p>
                  )}
                  <p className="text-sm text-gray-600 mt-2">мһ¬кі : {currentProduct.stock}к°ң</p>
                </div>
              ) : (
                <div className="text-center text-gray-500 py-8">
                  л…ём¶ң мӨ‘мқё мғҒн’Ҳмқҙ м—ҶмҠөлӢҲлӢӨ
                </div>
              )}
            </div>

            {/* Live Preview Link */}
            {selectedStream && (
              <div className="mt-4 bg-blue-50 border border-blue-200 rounded-lg p-4">
                <p className="text-sm font-semibold text-blue-900 mb-2">рҹ“ә лқјмқҙлёҢ лҜёлҰ¬ліҙкё°</p>
                <a
                  href={`/live/${selectedStream.id}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-600 hover:underline text-sm"
                >
                  {window.location.origin}/live/{selectedStream.id}
                </a>
              </div>
            )}
          </div>

          {/* Product List */}
          <div className="lg:col-span-2">
            <div className="bg-white rounded-lg shadow p-6">
              <h2 className="text-xl font-bold text-gray-900 mb-4">мғҒн’Ҳ лӘ©лЎқ (нҒҙлҰӯ: м „нҷҳ | л“ңлһҳк·ё: мҲңм„ң ліҖкІҪ)</h2>
              
              {products.length === 0 ? (
                <div className="text-center text-gray-500 py-8">
                  л“ұлЎқлҗң мғҒн’Ҳмқҙ м—ҶмҠөлӢҲлӢӨ
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                  {products.map((product, index) => (
                    <div
                      key={`${product.id}-${index}`}
                      draggable
                      onDragStart={(e) => handleDragStart(e, index)}
                      onDragOver={handleDragOver}
                      onDrop={(e) => handleDrop(e, index)}
                      onDragEnd={handleDragEnd}
                      className={`relative border-2 rounded-lg transition-all ${
                        draggedIndex === index ? 'opacity-50' : ''
                      }`}
                    >
                      {/* Drag Handle */}
                      <div className="absolute top-2 left-2 text-gray-400 cursor-move">
                        <GripVertical className="w-4 h-4" />
                      </div>

                      {/* Product Button */}
                      <button
                        onClick={() => changeProduct(product.id)}
                        disabled={changing || currentProductId === product.id}
                        className={`w-full text-left p-3 pl-8 rounded-lg transition-all ${
                          currentProductId === product.id
                            ? 'border-blue-500 bg-blue-50'
                            : 'border-gray-200 hover:border-blue-300 hover:bg-gray-50'
                        } ${changing ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
                      >
                        <h3 className="font-bold text-gray-900 text-sm mb-1 truncate">{product.name}</h3>
                        <div className="flex items-baseline gap-1 mb-1">
                          {product.discount_rate > 0 && (
                            <span className="text-red-500 text-xs font-bold">{product.discount_rate}%</span>
                          )}
                          <span className="font-bold text-sm">{product.price.toLocaleString()}мӣҗ</span>
                        </div>
                        <p className="text-xs text-gray-600">мһ¬кі : {product.stock}к°ң</p>
                        {currentProductId === product.id && (
                          <p className="text-xs text-blue-600 font-semibold mt-1">вң“ нҳ„мһ¬ л…ём¶ң мӨ‘</p>
                        )}
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Instructions */}
        <div className="mt-8 bg-yellow-50 border border-yellow-200 rounded-lg p-6">
          <h3 className="font-bold text-yellow-900 mb-2">рҹ’Ў мӮ¬мҡ© л°©лІ•</h3>
          <ul className="text-sm text-yellow-800 space-y-1">
            <li>вҖў мғҒн’Ҳмқ„ <strong>нҒҙлҰӯ</strong>н•ҳл©ҙ мӢӨмӢңк°„мңјлЎң мӢңмІӯмһҗ нҷ”л©ҙмқҳ мғҒн’Ҳмқҙ ліҖкІҪлҗ©лӢҲлӢӨ</li>
            <li>вҖў мғҒн’Ҳмқ„ <strong>л“ңлһҳк·ё</strong>н•ҳм—¬ мҲңм„ңлҘј ліҖкІҪн•  мҲҳ мһҲмҠөлӢҲлӢӨ</li>
            <li>вҖў мўҢмёЎм—җм„ң нҳ„мһ¬ л…ём¶ң мӨ‘мқё мғҒн’Ҳмқ„ нҷ•мқён•  мҲҳ мһҲмҠөлӢҲлӢӨ</li>
            <li>вҖў лқјмқҙлёҢ лҜёлҰ¬ліҙкё° л§ҒнҒ¬лҘј мғҲ нғӯм—җм„ң м—ҙм–ҙ мӢӨмӢңк°„мңјлЎң нҷ•мқён•ҳм„ёмҡ”</li>
          </ul>
        </div>
      </div>
    </div>
  )
}
