import { useState, useEffect } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import api from '@/lib/api'
import { ArrowLeft, Loader2, Play, Edit, Trash2 } from 'lucide-react'

interface Stream {
  id: number
  title: string
  description: string
  youtube_video_id: string
  status: string
  platform: string
  tiktok_username: string | null
  created_at: string
  seller_instagram: string | null
  seller_youtube: string | null
  seller_facebook: string | null
}

export default function SellerStreamEditPage() {
  const navigate = useNavigate()
  const { id } = useParams()
  const [stream, setStream] = useState<Stream | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    status: 'live'
  })

  useEffect(() => {
    const sessionToken = localStorage.getItem('seller_session_token')
    const userType = localStorage.getItem('user_type')
    
    if (!sessionToken || userType !== 'seller') {
      navigate('/seller/login')
      return
    }
    
    loadStream()
  }, [id])

  async function loadStream() {
    try {
      const sessionToken = localStorage.getItem('seller_session_token')

      const response = await api.get(`/api/seller/streams`, {
        headers: { 'Authorization': `Bearer ${sessionToken}` }
      })

      if (response.data.success) {
        const foundStream = response.data.data.find((s: Stream) => s.id === Number(id))
        if (foundStream) {
          setStream(foundStream)
          setFormData({
            title: foundStream.title || '',
            description: foundStream.description || '',
            status: foundStream.status || 'live'
          })
        } else {
          setError('мҠӨнҠёлҰјмқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ')
        }
      }
    } catch (error: any) {
      console.error('Failed to load stream:', error)
      setError('мҠӨнҠёлҰј лЎңл“ң мӢӨнҢЁ')
    } finally {
      setLoading(false)
    }
  }

  async function handleUpdate(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setLoading(true)

    try {
      const sessionToken = localStorage.getItem('seller_session_token')

      const response = await api.put(`/api/seller/streams/${id}`, {
        title: formData.title,
        description: formData.description,
        status: formData.status
      }, {
        headers: { 'Authorization': `Bearer ${sessionToken}` }
      })

      if (response.data.success) {
        alert('мҠӨнҠёлҰјмқҙ мҲҳм •лҗҳм—ҲмҠөлӢҲлӢӨ')
        navigate('/seller')
      } else {
        setError(response.data.error || 'мҲҳм • мӢӨнҢЁ')
      }
    } catch (error: any) {
      console.error('Failed to update stream:', error)
      setError(error.response?.data?.error || 'мҲҳм • мӢӨнҢЁ')
    } finally {
      setLoading(false)
    }
  }

  async function handleDelete() {
    if (!confirm('м •л§җ мқҙ мҠӨнҠёлҰјмқ„ мӮӯм ңн•ҳмӢңкІ мҠөлӢҲк№Ң?')) {
      return
    }

    try {
      const sessionToken = localStorage.getItem('seller_session_token')

      const response = await api.delete(`/api/seller/streams/${id}`, {
        headers: { 'Authorization': `Bearer ${sessionToken}` }
      })

      if (response.data.success) {
        alert('мҠӨнҠёлҰјмқҙ мӮӯм ңлҗҳм—ҲмҠөлӢҲлӢӨ')
        navigate('/seller')
      } else {
        setError(response.data.error || 'мӮӯм ң мӢӨнҢЁ')
      }
    } catch (error: any) {
      console.error('Failed to delete stream:', error)
      setError(error.response?.data?.error || 'мӮӯм ң мӢӨнҢЁ')
    }
  }

  function handleChange(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    })
  }

  function getVideoUrl() {
    if (!stream) return ''
    
    if (stream.platform === 'youtube') {
      return `https://www.youtube.com/watch?v=${stream.youtube_video_id}`
    } else if (stream.platform === 'tiktok') {
      return `https://www.tiktok.com/@${stream.tiktok_username}`
    }
    return ''
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <Loader2 className="w-10 h-10 animate-spin text-blue-600 mx-auto mb-4" />
          <p className="text-gray-600">мҠӨнҠёлҰј лЎңл”© мӨ‘...</p>
        </div>
      </div>
    )
  }

  if (!stream) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <p className="text-gray-600 mb-4">мҠӨнҠёлҰјмқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ</p>
          <button
            onClick={() => navigate('/seller')}
            className="text-blue-600 hover:underline"
          >
            лҢҖмӢңліҙл“ңлЎң лҸҢм•„к°Җкё°
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white border-b">
        <div className="max-w-4xl mx-auto px-4 py-4">
          <button
            onClick={() => navigate('/seller')}
            className="flex items-center gap-2 text-gray-600 hover:text-gray-900 transition-colors"
          >
            <ArrowLeft className="w-5 h-5" />
            <span>лҢҖмӢңліҙл“ңлЎң лҸҢм•„к°Җкё°</span>
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-4xl mx-auto px-4 py-8">
        {/* Title */}
        <div className="mb-8">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <Play className="w-10 h-10 text-blue-600" />
              <h1 className="text-3xl font-bold text-gray-900">мҠӨнҠёлҰј кҙҖлҰ¬</h1>
            </div>
            <button
              onClick={handleDelete}
              className="flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors"
            >
              <Trash2 className="w-4 h-4" />
              мӮӯм ң
            </button>
          </div>
        </div>

        {/* Stream Info */}
        <div className="bg-white rounded-lg shadow-sm border p-6 mb-6">
          <h2 className="text-lg font-semibold mb-4">мҠӨнҠёлҰј м •ліҙ</h2>
          <div className="space-y-3 text-sm">
            <div className="flex">
              <span className="w-32 text-gray-600">н”Ңлһ«нҸј:</span>
              <span className="font-medium">{stream.platform === 'youtube' ? 'YouTube' : 'TikTok'}</span>
            </div>
            <div className="flex">
              <span className="w-32 text-gray-600">мҳҒмғҒ ID:</span>
              <span className="font-mono text-gray-900">{stream.youtube_video_id}</span>
            </div>
            <div className="flex">
              <span className="w-32 text-gray-600">мҳҒмғҒ URL:</span>
              <a 
                href={getVideoUrl()} 
                target="_blank" 
                rel="noopener noreferrer"
                className="text-blue-600 hover:underline"
              >
                {getVideoUrl()}
              </a>
            </div>
            <div className="flex">
              <span className="w-32 text-gray-600">мғқм„ұмқј:</span>
              <span className="text-gray-900">{new Date(stream.created_at).toLocaleString('ko-KR')}</span>
            </div>
          </div>
        </div>

        {/* Error Message */}
        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
            <p className="text-red-700">{error}</p>
          </div>
        )}

        {/* Edit Form */}
        <form onSubmit={handleUpdate} className="bg-white rounded-lg shadow-sm border p-6 space-y-6">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <Edit className="w-5 h-5" />
            мҠӨнҠёлҰј мҲҳм •
          </h2>

          {/* Title */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              мҠӨнҠёлҰј м ңлӘ© <span className="text-red-500">*</span>
            </label>
            <input
              type="text"
              name="title"
              value={formData.title}
              onChange={handleChange}
              required
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            />
          </div>

          {/* Description */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              м„ӨлӘ…
            </label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              rows={4}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            />
          </div>

          {/* Status */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              мғҒнғң
            </label>
            <select
              name="status"
              value={formData.status}
              onChange={handleChange}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            >
              <option value="scheduled">мҳҲм •</option>
              <option value="live">лқјмқҙлёҢ</option>
              <option value="ended">мў…лЈҢ</option>
            </select>
          </div>

          {/* Submit Button */}
          <div className="pt-4 border-t">
            <div className="flex gap-3">
              <button
                type="button"
                onClick={() => navigate('/seller')}
                className="flex-1 py-3 bg-gray-600 hover:bg-gray-700 text-white rounded-lg transition-colors"
              >
                м·ЁмҶҢ
              </button>
              <button
                type="submit"
                disabled={loading}
                className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors disabled:opacity-50"
              >
                {loading ? (
                  <span className="flex items-center justify-center gap-2">
                    <Loader2 className="w-5 h-5 animate-spin" />
                    мҲҳм • мӨ‘...
                  </span>
                ) : (
                  'мҲҳм • мҷ„лЈҢ'
                )}
              </button>
            </div>
          </div>
        </form>
      </div>
    </div>
  )
}
