  const navigate = useNavigate()
  const [mode, setMode] = useState<'manual' | 'youtube-auto'>('manual')
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    youtubeUrl: '',
    scheduledAt: '',
    sellerInstagram: '',
    sellerYoutube: '',
    sellerFacebook: ''
  })
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [youtubeInfo, setYoutubeInfo] = useState<{
    streamKey: string
    streamUrl: string
    watchUrl: string
  } | null>(null)

  function handleChange(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) {
    setFormData(prev => ({
      ...prev,
      [e.target.name]: e.target.value
    }))
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setLoading(true)

    try {
      const sessionToken = localStorage.getItem('seller_session_token')
      
      if (!sessionToken) {
        setError('лЎңк·ёмқёмқҙ н•„мҡ”н•©лӢҲлӢӨ')
        navigate('/seller/login')
        return
      }

      if (mode === 'youtube-auto') {
        // YouTube мһҗлҸҷ мғқм„ұ
        const response = await api.post('/api/seller/youtube/create-live', {
          title: formData.title,
          description: formData.description,
          scheduled_at: formData.scheduledAt || null,
        }, {
          headers: {
            'Authorization': `Bearer ${sessionToken}`
          }
        })

        if (response.data.success) {
          setYoutubeInfo({
            streamKey: response.data.data.streamKey,
            streamUrl: response.data.data.streamUrl,
            watchUrl: response.data.data.watchUrl,
          })
          alert('YouTube лқјмқҙлёҢк°Җ мғқм„ұлҗҳм—ҲмҠөлӢҲлӢӨ! мҠӨнҠёлҰј нӮӨлҘј ліөмӮ¬н•ҳм—¬ OBSм—җ м„Өм •н•ҳм„ёмҡ”.')
        } else {
          setError(response.data.error || 'мғқм„ұ мӢӨнҢЁ')
        }
      } else {
        // мҲҳлҸҷ мһ…л Ҙ
        const response = await api.post('/api/seller/streams', {
          title: formData.title,
          description: formData.description,
          youtube_url: formData.youtubeUrl,
          scheduled_at: formData.scheduledAt || null,
          status: formData.scheduledAt ? 'scheduled' : 'live',
          seller_instagram: formData.sellerInstagram || null,
          seller_youtube: formData.sellerYoutube || null,
          seller_facebook: formData.sellerFacebook || null
        }, {
          headers: {
            'Authorization': `Bearer ${sessionToken}`
          }
        })

        if (response.data.success) {
          alert('лқјмқҙлёҢ мҠӨнҠёлҰјмқҙ мғқм„ұлҗҳм—ҲмҠөлӢҲлӢӨ!')
          navigate('/seller')
        } else {
          setError(response.data.error || 'мғқм„ұ мӢӨнҢЁ')
        }
      }
    } catch (err: any) {
      console.error('Stream creation error:', err)
      console.error('Error response:', err.response?.data)
      const errorMessage = err.response?.data?.error || err.response?.data?.message || err.message || 'мғқм„ұ мӢӨнҢЁ'
      setError(errorMessage)
    } finally {
      setLoading(false)
    }
  }

