                  <h3 className="text-lg font-semibold text-gray-900">кё°ліё м •ліҙ</h3>
                  
                  <div>
                    <label htmlFor="title" className="block text-sm font-medium text-gray-700 mb-2">
                      лқјмқҙлёҢ м ңлӘ© *
                    </label>
                    <input
                      id="title"
