import { useState, useEffect } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import api from '@/lib/api'
import { Button } from '@/components/ui/button'
import ImageUpload from '@/components/ImageUpload'
import { 
  ArrowLeft, 
  Package,
  Loader2,
  DollarSign,
  Box,
  FileText,
  Play
} from 'lucide-react'

interface LiveStream {
  id: number
  title: string
  status: string
}

interface Product {
  id: number
  name: string
  description: string
  price: number
  stock: number
  image_url: string
  live_stream_id: number | null
  is_active: boolean
  detail_images?: string | string[]
  product_type?: string // 'live' or 'featured'
}

export default function SellerProductEditPage() {
  const navigate = useNavigate()
  const { id } = useParams<{ id: string }>()
  const [loading, setLoading] = useState(true)
  const [submitting, setSubmitting] = useState(false)
  const [error, setError] = useState('')
  const [liveStreams, setLiveStreams] = useState<LiveStream[]>([])
  const [product, setProduct] = useState<Product | null>(null)

  const [formData, setFormData] = useState({
    name: '',
    description: '',
    price: '',
    stock: '',
    image_url: '',
    live_stream_id: '',
    is_active: true,
    detail_images: [] as string[],
    product_type: 'featured', // 'live' or 'featured'
    category: 'lifestyle' // м№ҙн…Ңкі лҰ¬ кё°ліёк°’
  })

  useEffect(() => {
    // Check authentication
    const sessionToken = localStorage.getItem('seller_session_token')
    const userType = localStorage.getItem('user_type')
    
    if (!sessionToken || userType !== 'seller') {
      navigate('/seller/login')
      return
    }
    
    loadProduct()
    loadLiveStreams()
  }, [id])

  async function loadProduct() {
    try {
      const sessionToken = localStorage.getItem('seller_session_token')

      if (!sessionToken) {
        navigate('/seller/login')
        return
      }

      const response = await api.get(`/api/seller/products/${id}`, {
        headers: { 'Authorization': `Bearer ${sessionToken}` }
      })

      if (response.data.success) {
        const productData = response.data.data
        setProduct(productData)
        
        // Parse detail_images if it exists
        let detailImages: string[] = []
        if (productData.detail_images) {
          detailImages = typeof productData.detail_images === 'string' 
            ? JSON.parse(productData.detail_images)
            : productData.detail_images
        }
        
        setFormData({
          name: productData.name,
          description: productData.description || '',
          price: String(productData.price),
          stock: String(productData.stock),
          image_url: productData.image_url || '',
          live_stream_id: productData.live_stream_id ? String(productData.live_stream_id) : '',
          is_active: productData.is_active,
          detail_images: detailImages,
          product_type: productData.product_type || 'featured',
          category: productData.category || 'lifestyle'
        })
      }
    } catch (error: any) {
      console.error('Failed to load product:', error)
      setError('мғҒн’Ҳ м •ліҙлҘј л¶Ҳлҹ¬мҳ¬ мҲҳ м—ҶмҠөлӢҲлӢӨ.')
    } finally {
      setLoading(false)
    }
  }

  async function loadLiveStreams() {
    try {
      const sessionToken = localStorage.getItem('seller_session_token')

      if (!sessionToken) return

      const response = await api.get('/api/seller/streams', {
        headers: { 'Authorization': `Bearer ${sessionToken}` }
      })

      if (response.data.success) {
        setLiveStreams(response.data.data)
      }
    } catch (error) {
      console.error('Failed to load live streams:', error)
    }
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setSubmitting(true)

    try {
      const sessionToken = localStorage.getItem('seller_session_token')

      if (!sessionToken) {
        navigate('/seller/login')
        return
      }

      const payload = {
        name: formData.name,
        description: formData.description,
        price: Number(formData.price),
        stock: Number(formData.stock),
        image_url: formData.image_url,
        live_stream_id: formData.live_stream_id ? Number(formData.live_stream_id) : null,
        is_active: formData.is_active,
        detail_images: JSON.stringify(formData.detail_images),
        product_type: formData.product_type,
        category: formData.category
      }

      const response = await api.patch(`/api/seller/products/${id}`, payload, {
        headers: { 'Authorization': `Bearer ${sessionToken}` }
      })

      if (response.data.success) {
        alert('мғҒн’Ҳмқҙ мҲҳм •лҗҳм—ҲмҠөлӢҲлӢӨ.')
        navigate('/seller/products')
      }
    } catch (error: any) {
      console.error('Failed to update product:', error)
      setError(error.response?.data?.error || 'мғҒн’Ҳ мҲҳм •м—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.')
    } finally {
      setSubmitting(false)
    }
  }

  function handleChange(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) {
    const { name, value, type } = e.target as HTMLInputElement
    
    if (type === 'checkbox') {
      setFormData({
        ...formData,
        [name]: (e.target as HTMLInputElement).checked
      })
    } else {
      setFormData({
        ...formData,
        [name]: value
      })
    }
  }

  function addDetailImage() {
    const url = prompt('мғҒм„ё мқҙлҜём§Җ URLмқ„ мһ…л Ҙн•ҳм„ёмҡ”:')
    if (url && url.trim()) {
      setFormData({
        ...formData,
        detail_images: [...formData.detail_images, url.trim()]
      })
    }
  }

  function removeDetailImage(index: number) {
    setFormData({
      ...formData,
      detail_images: formData.detail_images.filter((_, i) => i !== index)
    })
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600" />
      </div>
    )
  }

  if (!product) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <Package className="w-16 h-16 text-gray-300 mx-auto mb-4" />
          <p className="text-gray-600">мғҒн’Ҳмқ„ м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ.</p>
          <Button
            onClick={() => navigate('/seller/products')}
            className="mt-4 bg-blue-600 hover:bg-blue-700 text-white"
          >
            лӘ©лЎқмңјлЎң лҸҢм•„к°Җкё°
          </Button>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white border-b">
        <div className="max-w-4xl mx-auto px-4 py-4">
          <button
            onClick={() => navigate('/seller/products')}
            className="flex items-center gap-2 text-gray-600 hover:text-gray-900 transition-colors"
          >
            <ArrowLeft className="w-5 h-5" />
            <span>мғҒн’Ҳ лӘ©лЎқмңјлЎң лҸҢм•„к°Җкё°</span>
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-4xl mx-auto px-4 py-8">
        {/* Title */}
        <div className="mb-8">
          <div className="flex items-center gap-3 mb-2">
            <Package className="w-10 h-10 text-blue-600" />
            <h1 className="text-3xl font-bold text-gray-900">мғҒн’Ҳ мҲҳм •</h1>
          </div>
          <p className="text-gray-600 mt-2">
            мғҒн’Ҳ м •ліҙлҘј мҲҳм •н•ҳкі  ліҖкІҪмӮ¬н•ӯмқ„ м ҖмһҘн•  мҲҳ мһҲмҠөлӢҲлӢӨ.
          </p>
        </div>

        {/* Error Message */}
        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
            <div className="flex items-center gap-2 text-red-700">
              <Package className="w-5 h-5" />
              <p>{error}</p>
            </div>
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleSubmit} className="bg-white rounded-lg shadow-sm border p-6 space-y-6">
          {/* Product Name */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              мғҒн’ҲлӘ… <span className="text-red-500">*</span>
            </label>
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              placeholder="мҳҲ: н”„лҰ¬лҜём—„ л¬ҙм„  мқҙм–ҙнҸ°"
              required
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            />
          </div>

          {/* Description */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              мғҒн’Ҳ м„ӨлӘ…
            </label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              placeholder="мғҒн’Ҳм—җ лҢҖн•ң мһҗм„ён•ң м„ӨлӘ…мқ„ мһ…л Ҙн•ҙмЈјм„ёмҡ”"
              rows={4}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            />
          </div>

          {/* Price & Stock */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                нҢҗл§Өк°ҖкІ© <span className="text-red-500">*</span>
              </label>
              <div className="relative">
                <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                <input
                  type="number"
                  name="price"
                  value={formData.price}
                  onChange={handleChange}
                  placeholder="30000"
                  required
                  min="0"
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                />
              </div>
              <p className="text-xs text-gray-500 mt-1">мӣҗ лӢЁмң„лЎң мһ…л Ҙн•ҙмЈјм„ёмҡ”</p>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                мһ¬кі  мҲҳлҹү <span className="text-red-500">*</span>
              </label>
              <div className="relative">
                <Box className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                <input
                  type="number"
                  name="stock"
                  value={formData.stock}
                  onChange={handleChange}
                  placeholder="100"
                  required
                  min="0"
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                />
              </div>
              <p className="text-xs text-gray-500 mt-1">к°ң лӢЁмң„лЎң мһ…л Ҙн•ҙмЈјм„ёмҡ”</p>
            </div>
          </div>

          {/* Image Upload */}
          <ImageUpload
            value={formData.image_url}
            onChange={(url) => setFormData({ ...formData, image_url: url })}
            label="мғҒн’Ҳ мқҙлҜём§Җ"
            maxSizeKB={800}
          />

          {/* Category Selection */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              м№ҙн…Ңкі лҰ¬ <span className="text-red-500">*</span>
            </label>
            <select
              name="category"
              value={formData.category}
              onChange={handleChange}
              required
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
            >
              <option value="fashion">нҢЁм…ҳ</option>
              <option value="beauty">л·°нӢ°</option>
              <option value="food">мӢқн’Ҳ</option>
              <option value="electronics">м „мһҗкё°кё°</option>
              <option value="lifestyle">лқјмқҙн”„мҠӨнғҖмқј</option>
            </select>
            <p className="text-xs text-gray-500 mt-1">мғҒн’Ҳмқҙ мҶҚн•  м№ҙн…Ңкі лҰ¬лҘј м„ нғқн•ҳм„ёмҡ”</p>
          </div>

          {/* Product Type Selection */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-3">
              мғҒн’Ҳ нғҖмһ… <span className="text-red-500">*</span>
            </label>
            <div className="space-y-3">
              <label className={`flex items-start gap-3 p-4 border-2 rounded-lg cursor-pointer transition-all hover:bg-gray-50 ${formData.product_type === 'live' ? 'border-blue-500 bg-blue-50' : 'border-gray-200'}`}>
                <input
                  type="radio"
                  name="product_type"
                  value="live"
                  checked={formData.product_type === 'live'}
                  onChange={handleChange}
                  className="mt-1 w-4 h-4 text-blue-600"
                />
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <Play className="w-5 h-5 text-red-600" />
                    <span className="font-semibold text-gray-900">лқјмқҙлёҢ л°©мҶЎ м „мҡ© мғҒн’Ҳ</span>
                  </div>
                  <p className="text-sm text-gray-600 mt-1">
                    лқјмқҙлёҢ мҠӨнҠёлҰ¬л°Қ мӨ‘м—җл§Ң нҢҗл§ӨлҗҳлҠ” н•ңм • мғҒн’Ҳ
                  </p>
                </div>
              </label>

              <label className={`flex items-start gap-3 p-4 border-2 rounded-lg cursor-pointer transition-all hover:bg-gray-50 ${formData.product_type === 'featured' ? 'border-blue-500 bg-blue-50' : 'border-gray-200'}`}>
                <input
                  type="radio"
                  name="product_type"
                  value="featured"
                  checked={formData.product_type === 'featured'}
                  onChange={handleChange}
                  className="mt-1 w-4 h-4 text-blue-600"
                />
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <Package className="w-5 h-5 text-blue-600" />
                    <span className="font-semibold text-gray-900">Ur нҠ№к°Җ мғҒн’Ҳ</span>
                  </div>
                  <p className="text-sm text-gray-600 mt-1">
                    л©”мқё нҺҳмқҙм§Җ "Ur нҠ№к°Җ" м„№м…ҳм—җ л…ём¶ңлҗҳлҠ” мқјл°ҳ нҢҗл§Ө мғҒн’Ҳ
                  </p>
                </div>
              </label>
            </div>
          </div>

          {/* Image Preview - Removed as ImageUpload component handles it */}

          {/* Detail Images */}
          <div>
            <div className="flex items-center justify-between mb-2">
              <label className="block text-sm font-medium text-gray-700">
                мғҒн’Ҳ мғҒм„ё мқҙлҜём§Җ (м„ нғқ)
              </label>
              <Button
                type="button"
                onClick={addDetailImage}
                className="text-sm py-1 px-3 bg-green-600 hover:bg-green-700 text-white"
              >
                + мқҙлҜём§Җ м¶”к°Җ
              </Button>
            </div>
            
            {formData.detail_images.length > 0 ? (
              <div className="space-y-3">
                {formData.detail_images.map((imageUrl, index) => (
                  <div key={index} className="flex items-start gap-3 p-3 bg-gray-50 rounded-lg border">
                    <div className="w-24 h-24 bg-gray-200 rounded overflow-hidden flex-shrink-0">
                      <img
                        src={imageUrl}
                        alt={`мғҒм„ё мқҙлҜём§Җ ${index + 1}`}
                        className="w-full h-full object-cover"
                        onError={(e) => {
                          (e.target as HTMLImageElement).src = 'https://via.placeholder.com/96'
                        }}
                      />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs text-gray-500 mb-1">мқҙлҜём§Җ {index + 1}</p>
                      <p className="text-sm text-gray-700 break-all">{imageUrl}</p>
                    </div>
                    <Button
                      type="button"
                      onClick={() => removeDetailImage(index)}
                      className="flex-shrink-0 px-3 py-1 bg-red-600 hover:bg-red-700 text-white text-sm"
                    >
                      мӮӯм ң
                    </Button>
                  </div>
                ))}
              </div>
            ) : (
              <div className="p-6 bg-gray-50 rounded-lg border border-dashed border-gray-300 text-center">
                <ImageIcon className="w-12 h-12 text-gray-400 mx-auto mb-2" />
                <p className="text-sm text-gray-500">мғҒм„ё мқҙлҜём§Җк°Җ м—ҶмҠөлӢҲлӢӨ</p>
                <p className="text-xs text-gray-400 mt-1">мң„мқҳ "+ мқҙлҜём§Җ м¶”к°Җ" лІ„нҠјмқ„ нҒҙлҰӯн•ҳм—¬ мқҙлҜём§ҖлҘј м¶”к°Җн•ҳм„ёмҡ”</p>
              </div>
            )}
            <p className="text-xs text-gray-500 mt-2">
              рҹ’Ў Tip: Unsplash, Pexels л“ұ л¬ҙлЈҢ мқҙлҜём§Җ мӮ¬мқҙнҠём—җм„ң мқҙлҜём§Җ URLмқ„ ліөмӮ¬н•ҳм—¬ мӮ¬мҡ©н•  мҲҳ мһҲмҠөлӢҲлӢӨ
            </p>
          </div>

          {/* Live Stream Selection */}
          {liveStreams.length > 0 && (
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                лқјмқҙлёҢ мҠӨнҠёлҰј м—°кІ° (м„ нғқ)
              </label>
              <div className="relative">
                <Play className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                <select
                  name="live_stream_id"
                  value={formData.live_stream_id}
                  onChange={handleChange}
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 appearance-none bg-white"
                >
                  <option value="">лқјмқҙлёҢ мҠӨнҠёлҰјмқ„ м„ нғқн•ҳм„ёмҡ” (м„ нғқмӮ¬н•ӯ)</option>
                  {liveStreams.map((stream) => (
                    <option key={stream.id} value={stream.id}>
                      {stream.title} ({stream.status === 'live' ? 'LIVE' : stream.status === 'scheduled' ? 'мҳҲм •' : 'мў…лЈҢ'})
                    </option>
                  ))}
                </select>
              </div>
              <p className="text-xs text-gray-500 mt-1">нҠ№м • лқјмқҙлёҢ мҠӨнҠёлҰјм—җм„ң нҢҗл§Өн•  мғҒн’Ҳмқё кІҪмҡ° м„ нғқн•ҳм„ёмҡ”</p>
            </div>
          )}

          {/* Active Status */}
          <div>
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                name="is_active"
                checked={formData.is_active}
                onChange={handleChange}
                className="w-5 h-5 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
              />
              <div>
                <p className="text-sm font-medium text-gray-700">мғҒн’Ҳ нҷңм„ұнҷ”</p>
                <p className="text-xs text-gray-500">мІҙнҒ¬н•ҳл©ҙ кі к°қм—җкІҢ мғҒн’Ҳмқҙ н‘ңмӢңлҗ©лӢҲлӢӨ</p>
              </div>
            </label>
          </div>

          {/* Submit Button */}
          <div className="pt-4 border-t">
            <div className="flex gap-3">
              <Button
                type="button"
                onClick={() => navigate('/seller/products')}
                className="flex-1 py-3 bg-gray-600 hover:bg-gray-700 text-white"
              >
                м·ЁмҶҢ
              </Button>
              <Button
                type="submit"
                disabled={submitting}
                className="flex-1 py-3 bg-blue-600 hover:bg-blue-700 text-white"
              >
                {submitting ? (
                  <span className="flex items-center justify-center gap-2">
                    <Loader2 className="w-5 h-5 animate-spin" />
                    м ҖмһҘ мӨ‘...
                  </span>
                ) : (
                  'ліҖкІҪмӮ¬н•ӯ м ҖмһҘ'
                )}
              </Button>
            </div>
          </div>

          {/* Help Text */}
          <div className="pt-4 border-t">
            <div className="flex items-start gap-2 text-sm text-gray-600">
              <FileText className="w-4 h-4 mt-0.5 flex-shrink-0" />
              <div>
                <p className="font-medium mb-1">м•ҲлӮҙмӮ¬н•ӯ</p>
                <ul className="list-disc list-inside space-y-1 text-xs">
                  <li>мғҒн’ҲлӘ…кіј к°ҖкІ©, мһ¬кі лҠ” н•„мҲҳ мһ…л Ҙ н•ӯлӘ©мһ…лӢҲлӢӨ.</li>
                  <li>ліҖкІҪмӮ¬н•ӯмқҖ мҰүмӢң л°ҳмҳҒлҗ©лӢҲлӢӨ.</li>
                  <li>л№„нҷңм„ұнҷ” мғҒнғңлЎң ліҖкІҪн•ҳл©ҙ кі к°қм—җкІҢ н‘ңмӢңлҗҳм§Җ м•ҠмҠөлӢҲлӢӨ.</li>
                </ul>
              </div>
            </div>
          </div>
        </form>
      </div>
    </div>
  )
}
