/**
 * м…Җлҹ¬ JWT мқёмҰқ н—¬нҚј н•ЁмҲҳ
 * seller_session_token лҢҖмӢ  access_token (JWT) мӮ¬мҡ©
 */

export function getSellerToken(): string | null {
  // JWT мҡ°м„  мӮ¬мҡ©
  const accessToken = localStorage.getItem('access_token')
  if (accessToken) {
    return accessToken
  }
  
  // л Ҳкұ°мӢң нҳёнҷҳм„ұ
  return localStorage.getItem('seller_session_token')
}

export function isSellerAuthenticated(): boolean {
  const token = getSellerToken()
  const userType = localStorage.getItem('user_type')
  return !!token && userType === 'seller'
}

export function getSellerId(): string | null {
  return localStorage.getItem('seller_id')
}

export function redirectToLogin(navigate: any) {
  console.log('[SellerAuth] вқҢ Not authenticated, redirecting to login')
  navigate('/seller/login', { replace: true })
}

export function logoutSeller(navigate: any) {
  // рҹ”§ н‘ңмӨҖ logout н•ЁмҲҳ мӮ¬мҡ© (JWT + л Ҳкұ°мӢң нӮӨ лӘЁл‘җ мӮӯм ң)
  const { logout } = require('@/utils/auth')
  logout()
  
  console.log('[SellerAuth] рҹҡӘ м…Җлҹ¬ лЎңк·ём•„мӣғ мҷ„лЈҢ')
  navigate('/seller/login')
}
