import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import api from '@/lib/api'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { 
  ArrowLeft, 
  Building2,
  CheckCircle2,
  AlertCircle,
  Loader2,
  FileText,
  Search
} from 'lucide-react'

interface BusinessInfo {
  id: number
  business_number: string
  business_name: string
  ceo_name: string
  business_type: string
  business_category: string
  postal_code: string
  address: string
  address_detail: string
  phone: string
  email: string
  is_verified: boolean
  verified_at: string | null
  created_at: string
}

// Daum Postcode нғҖмһ… м •мқҳ
declare global {
  interface Window {
    daum: any
  }
}

export default function SellerBusinessInfoPage() {
  const navigate = useNavigate()
  const [businessInfo, setBusinessInfo] = useState<BusinessInfo | null>(null)
  const [loading, setLoading] = useState(true)
  const [submitting, setSubmitting] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')

  const [formData, setFormData] = useState({
    business_number: '',
    business_name: '',
    ceo_name: '',
    business_type: '',
    business_category: '',
    postal_code: '',
    address: '',
    address_detail: '',
    phone: '',
    email: ''
  })

  useEffect(() => {
    loadBusinessInfo()
    loadDaumPostcodeScript()
  }, [])

  function loadDaumPostcodeScript() {
    const script = document.createElement('script')
    script.src = '//t1.daumcdn.net/mapjsapi/bundle/postcode/prod/postcode.v2.js'
    script.async = true
    document.body.appendChild(script)
  }

  async function loadBusinessInfo() {
    try {
      const sessionToken = localStorage.getItem('seller_session_token')
      

      if (!sessionToken) {
        navigate('/seller/login')
        return
      }

      const response = await api.get('/api/seller/business-info')

      if (response.data.success && response.data.data) {
        setBusinessInfo(response.data.data)
        setFormData({
          business_number: response.data.data.business_number || '',
          business_name: response.data.data.business_name || '',
          ceo_name: response.data.data.ceo_name || '',
          business_type: response.data.data.business_type || '',
          business_category: response.data.data.business_category || '',
          postal_code: response.data.data.postal_code || '',
          address: response.data.data.address || '',
          address_detail: response.data.data.address_detail || '',
          phone: response.data.data.phone || '',
          email: response.data.data.email || ''
        })
      }
    } catch (error: any) {
      if (error.response?.status === 404) {
        // мӮ¬м—…мһҗ м •ліҙк°Җ м•„м§Ғ л“ұлЎқлҗҳм§Җ м•ҠмқҢ
      } else {
        console.error('Failed to load business info:', error)
        setError('мӮ¬м—…мһҗ м •ліҙлҘј л¶Ҳлҹ¬мҳ¬ мҲҳ м—ҶмҠөлӢҲлӢӨ.')
      }
    } finally {
      setLoading(false)
    }
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setSuccess('')
    setSubmitting(true)

    try {
      const sessionToken = localStorage.getItem('seller_session_token')
      

      if (!sessionToken) {
        navigate('/seller/login')
        return
      }

      const response = await api.post('/api/seller/business-info', formData)

      if (response.data.success) {
        setSuccess('мӮ¬м—…мһҗ м •ліҙк°Җ м ҖмһҘлҗҳм—ҲмҠөлӢҲлӢӨ. кҙҖлҰ¬мһҗ мҠ№мқёмқ„ кё°лӢӨл ӨмЈјм„ёмҡ”.')
        setTimeout(() => {
          loadBusinessInfo()
        }, 1500)
      }
    } catch (error: any) {
      console.error('Failed to save business info:', error)
      setError(error.response?.data?.error || 'мӮ¬м—…мһҗ м •ліҙ м ҖмһҘм—җ мӢӨнҢЁн–ҲмҠөлӢҲлӢӨ.')
    } finally {
      setSubmitting(false)
    }
  }

  function handleChange(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) {
    const { name, value } = e.target
    
    let formattedValue = value

    // мӮ¬м—…мһҗл“ұлЎқлІҲнҳё мһҗлҸҷ н•ҳмқҙн”Ҳ (000-00-00000)
    if (name === 'business_number') {
      const numbers = value.replace(/[^\d]/g, '')
      if (numbers.length <= 3) {
        formattedValue = numbers
      } else if (numbers.length <= 5) {
        formattedValue = `${numbers.slice(0, 3)}-${numbers.slice(3)}`
      } else {
        formattedValue = `${numbers.slice(0, 3)}-${numbers.slice(3, 5)}-${numbers.slice(5, 10)}`
      }
    }

    // м „нҷ”лІҲнҳё мһҗлҸҷ н•ҳмқҙн”Ҳ
    if (name === 'phone') {
      const numbers = value.replace(/[^\d]/g, '')
      
      // 010, 011 л“ұ нңҙлҢҖнҸ° лІҲнҳё (010-0000-0000)
      if (numbers.startsWith('01')) {
        if (numbers.length <= 3) {
          formattedValue = numbers
        } else if (numbers.length <= 7) {
          formattedValue = `${numbers.slice(0, 3)}-${numbers.slice(3)}`
        } else {
          formattedValue = `${numbers.slice(0, 3)}-${numbers.slice(3, 7)}-${numbers.slice(7, 11)}`
        }
      }
      // 02 м„ңмҡё м§Җм—ӯлІҲнҳё (02-000-0000 лҳҗлҠ” 02-0000-0000)
      else if (numbers.startsWith('02')) {
        if (numbers.length <= 2) {
          formattedValue = numbers
        } else if (numbers.length <= 5) {
          formattedValue = `${numbers.slice(0, 2)}-${numbers.slice(2)}`
        } else if (numbers.length <= 9) {
          formattedValue = `${numbers.slice(0, 2)}-${numbers.slice(2, 5)}-${numbers.slice(5)}`
        } else {
          formattedValue = `${numbers.slice(0, 2)}-${numbers.slice(2, 6)}-${numbers.slice(6, 10)}`
        }
      }
      // к·ё мҷё м§Җм—ӯлІҲнҳё (031-000-0000 лҳҗлҠ” 031-0000-0000)
      else {
        if (numbers.length <= 3) {
          formattedValue = numbers
        } else if (numbers.length <= 6) {
          formattedValue = `${numbers.slice(0, 3)}-${numbers.slice(3)}`
        } else if (numbers.length <= 10) {
          formattedValue = `${numbers.slice(0, 3)}-${numbers.slice(3, 6)}-${numbers.slice(6)}`
        } else {
          formattedValue = `${numbers.slice(0, 3)}-${numbers.slice(3, 7)}-${numbers.slice(7, 11)}`
        }
      }
    }

    setFormData({
      ...formData,
      [name]: formattedValue
    })
  }

  function openAddressSearch() {
    if (!window.daum || !window.daum.Postcode) {
      alert('мЈјмҶҢ кІҖмғү кё°лҠҘмқ„ л¶Ҳлҹ¬мҳӨлҠ” мӨ‘мһ…лӢҲлӢӨ. мһ мӢң нӣ„ лӢӨмӢң мӢңлҸ„н•ҙмЈјм„ёмҡ”.')
      return
    }

    new window.daum.Postcode({
      oncomplete: function(data: any) {
        // мҡ°нҺёлІҲнҳёмҷҖ мЈјмҶҢ м •ліҙлҘј formDataм—җ м„Өм •
        setFormData({
          ...formData,
          postal_code: data.zonecode,
          address: data.address
        })
      }
    }).open()
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600" />
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white border-b">
        <div className="max-w-4xl mx-auto px-4 py-4">
          <button
            onClick={() => navigate('/seller')}
            className="flex items-center gap-2 text-gray-600 hover:text-gray-900 transition-colors"
          >
            <ArrowLeft className="w-5 h-5" />
            <span>нҢҗл§Өмһҗ лҢҖмӢңліҙл“ңлЎң лҸҢм•„к°Җкё°</span>
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-4xl mx-auto px-4 py-8">
        {/* Title */}
        <div className="mb-8">
          <div className="flex items-center gap-3 mb-2">
            <Building2 className="w-10 h-10 text-blue-600" />
            <h1 className="text-3xl font-bold text-gray-900">мӮ¬м—…мһҗ м •ліҙ кҙҖлҰ¬</h1>
          </div>
          <p className="text-gray-600 mt-2">
            м„ёкёҲкі„мӮ°м„ң л°ңн–үмқ„ мң„н•ҙ мӮ¬м—…мһҗ м •ліҙлҘј л“ұлЎқн•ҙмЈјм„ёмҡ”. кҙҖлҰ¬мһҗ мҠ№мқё нӣ„ мӮ¬мҡ© к°ҖлҠҘн•©лӢҲлӢӨ.
          </p>
        </div>

        {/* Status Banner */}
        {businessInfo && (
          <div className={`mb-6 p-4 rounded-lg border ${
            businessInfo.is_verified
              ? 'bg-green-50 border-green-200'
              : 'bg-yellow-50 border-yellow-200'
          }`}>
            <div className="flex items-center gap-3">
              {businessInfo.is_verified ? (
                <>
                  <CheckCircle2 className="w-5 h-5 text-green-600" />
                  <div>
                    <p className="font-medium text-green-900">мҠ№мқё мҷ„лЈҢ</p>
                    <p className="text-sm text-green-700">
                      {businessInfo.verified_at && `мҠ№мқёмқјмӢң: ${new Date(businessInfo.verified_at).toLocaleString('ko-KR')}`}
                    </p>
                  </div>
                </>
              ) : (
                <>
                  <AlertCircle className="w-5 h-5 text-yellow-600" />
                  <div>
                    <p className="font-medium text-yellow-900">мҠ№мқё лҢҖкё°мӨ‘</p>
                    <p className="text-sm text-yellow-700">
                      кҙҖлҰ¬мһҗк°Җ мӮ¬м—…мһҗ м •ліҙлҘј кІҖнҶ н•ҳкі  мһҲмҠөлӢҲлӢӨ. мҳҒм—…мқј кё°мӨҖ 1~2мқј мҶҢмҡ”лҗ©лӢҲлӢӨ.
                    </p>
                  </div>
                </>
              )}
            </div>
          </div>
        )}

        {/* Error Message */}
        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
            <div className="flex items-center gap-2 text-red-700">
              <AlertCircle className="w-5 h-5" />
              <p>{error}</p>
            </div>
          </div>
        )}

        {/* Success Message */}
        {success && (
          <div className="mb-6 p-4 bg-green-50 border border-green-200 rounded-lg">
            <div className="flex items-center gap-2 text-green-700">
              <CheckCircle2 className="w-5 h-5" />
              <p>{success}</p>
            </div>
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleSubmit} className="bg-white rounded-lg shadow-sm border p-6 space-y-6">
          {/* мӮ¬м—…мһҗл“ұлЎқлІҲнҳё */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              мӮ¬м—…мһҗл“ұлЎқлІҲнҳё <span className="text-red-500">*</span>
            </label>
            <input
              type="text"
              name="business_number"
              value={formData.business_number}
              onChange={handleChange}
              placeholder="000-00-00000"
              maxLength={12}
              required
              disabled={businessInfo?.is_verified}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
            />
            <p className="text-xs text-gray-500 mt-1">мҲ«мһҗл§Ң мһ…л Ҙн•ҳл©ҙ мһҗлҸҷмңјлЎң н•ҳмқҙн”Ҳмқҙ м¶”к°Җлҗ©лӢҲлӢӨ.</p>
          </div>

          {/* мғҒнҳёлӘ… */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              мғҒнҳё(лІ•мқёлӘ…) <span className="text-red-500">*</span>
            </label>
            <input
              type="text"
              name="business_name"
              value={formData.business_name}
              onChange={handleChange}
              placeholder="мҳҲ: (мЈј)лҰ¬мҠӨн„°мҪ”нҚјл Ҳмқҙм…ҳ"
              required
              disabled={businessInfo?.is_verified}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
            />
          </div>

          {/* лҢҖн‘ңмһҗлӘ… */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              лҢҖн‘ңмһҗлӘ… <span className="text-red-500">*</span>
            </label>
            <input
              type="text"
              name="ceo_name"
              value={formData.ceo_name}
              onChange={handleChange}
              placeholder="мҳҲ: нҷҚкёёлҸҷ"
              required
              disabled={businessInfo?.is_verified}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
            />
          </div>

          {/* м—…нғң/м—…мў… */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                м—…нғң
              </label>
              <input
                type="text"
                name="business_type"
                value={formData.business_type}
                onChange={handleChange}
                placeholder="мҳҲ: лҸ„мҶҢл§Өм—…"
                disabled={businessInfo?.is_verified}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                м—…мў…
              </label>
              <input
                type="text"
                name="business_category"
                value={formData.business_category}
                onChange={handleChange}
                placeholder="мҳҲ: м „мһҗмғҒкұ°лһҳм—…"
                disabled={businessInfo?.is_verified}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
              />
            </div>
          </div>

          {/* мӮ¬м—…мһҘ мЈјмҶҢ */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              мӮ¬м—…мһҘ мҶҢмһ¬м§Җ <span className="text-red-500">*</span>
            </label>
            <div className="space-y-2">
              <div className="flex gap-2">
                <input
                  type="text"
                  name="postal_code"
                  value={formData.postal_code}
                  onChange={handleChange}
                  placeholder="мҡ°нҺёлІҲнҳё"
                  required
                  readOnly
                  disabled={businessInfo?.is_verified}
                  className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
                />
                {!businessInfo?.is_verified && (
                  <Button
                    type="button"
                    onClick={openAddressSearch}
                    className="px-4 py-2 bg-gray-600 hover:bg-gray-700 text-white rounded-lg flex items-center gap-2"
                  >
                    <Search className="w-4 h-4" />
                    мЈјмҶҢ кІҖмғү
                  </Button>
                )}
              </div>
              <input
                type="text"
                name="address"
                value={formData.address}
                onChange={handleChange}
                placeholder="кё°ліё мЈјмҶҢ"
                required
                readOnly
                disabled={businessInfo?.is_verified}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
              />
              <input
                type="text"
                name="address_detail"
                value={formData.address_detail}
                onChange={handleChange}
                placeholder="мғҒм„ё мЈјмҶҢ"
                disabled={businessInfo?.is_verified}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
              />
            </div>
          </div>

          {/* м—°лқҪмІҳ */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                м „нҷ”лІҲнҳё <span className="text-red-500">*</span>
              </label>
              <input
                type="tel"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                placeholder="02-1234-5678"
                maxLength={13}
                required
                disabled={businessInfo?.is_verified}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
              />
              <p className="text-xs text-gray-500 mt-1">мҲ«мһҗл§Ң мһ…л Ҙн•ҳл©ҙ мһҗлҸҷмңјлЎң н•ҳмқҙн”Ҳмқҙ м¶”к°Җлҗ©лӢҲлӢӨ.</p>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                мқҙл©”мқј <span className="text-red-500">*</span>
              </label>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                placeholder="business@example.com"
                required
                disabled={businessInfo?.is_verified}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-gray-100 disabled:cursor-not-allowed"
              />
            </div>
          </div>

          {/* Submit Button */}
          {!businessInfo?.is_verified && (
            <div className="pt-4">
              <Button
                type="submit"
                disabled={submitting}
                className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white font-medium rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {submitting ? (
                  <span className="flex items-center justify-center gap-2">
                    <Loader2 className="w-5 h-5 animate-spin" />
                    м ҖмһҘ мӨ‘...
                  </span>
                ) : businessInfo ? (
                  'м •ліҙ мҲҳм •н•ҳкё°'
                ) : (
                  'мӮ¬м—…мһҗ м •ліҙ л“ұлЎқн•ҳкё°'
                )}
              </Button>
            </div>
          )}

          {/* Help Text */}
          <div className="pt-4 border-t">
            <div className="flex items-start gap-2 text-sm text-gray-600">
              <FileText className="w-4 h-4 mt-0.5 flex-shrink-0" />
              <div>
                <p className="font-medium mb-1">м•ҲлӮҙмӮ¬н•ӯ</p>
                <ul className="list-disc list-inside space-y-1 text-xs">
                  <li>мӮ¬м—…мһҗ м •ліҙлҠ” м„ёкёҲкі„мӮ°м„ң л°ңн–үм—җ мӮ¬мҡ©лҗ©лӢҲлӢӨ.</li>
                  <li>мҠ№мқё нӣ„м—җлҠ” мҲҳм •мқҙ л¶Ҳк°ҖлҠҘн•©лӢҲлӢӨ. ліҖкІҪмқҙ н•„мҡ”н•ң кІҪмҡ° кі к°қм„јн„°лЎң л¬ёмқҳн•ҙмЈјм„ёмҡ”.</li>
                  <li>н—Ҳмң„ м •ліҙ мһ…л Ҙ мӢң м„ңл№„мҠӨ мқҙмҡ©мқҙ м ңн•ңлҗ  мҲҳ мһҲмҠөлӢҲлӢӨ.</li>
                  <li>мЈјмҶҢлҠ” "мЈјмҶҢ кІҖмғү" лІ„нҠјмқ„ нҒҙлҰӯн•ҳм—¬ м •нҷ•н•ҳкІҢ мһ…л Ҙн•ҙмЈјм„ёмҡ”.</li>
                </ul>
              </div>
            </div>
          </div>
        </form>
      </div>
    </div>
  )
}
