import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import api from '@/lib/api'

export default function SellerRegisterPage() {
  const navigate = useNavigate()
  const [formData, setFormData] = useState({
    email: '',
    password: '',
    passwordConfirm: '',
    name: '',
    phone: '',
    businessNumber: '',
    companyName: ''
  })
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    setFormData(prev => ({
      ...prev,
      [e.target.name]: e.target.value
    }))
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')

    // мң нҡЁм„ұ кІҖмҰқ
    if (formData.password !== formData.passwordConfirm) {
      setError('л№„л°ҖлІҲнҳёк°Җ мқјм№ҳн•ҳм§Җ м•ҠмҠөлӢҲлӢӨ')
      return
    }

    if (formData.password.length < 6) {
      setError('л№„л°ҖлІҲнҳёлҠ” 6мһҗ мқҙмғҒмқҙм–ҙм•ј н•©лӢҲлӢӨ')
      return
    }

    if (!formData.email.includes('@')) {
      setError('мҳ¬л°”лҘё мқҙл©”мқј мЈјмҶҢлҘј мһ…л Ҙн•ҙмЈјм„ёмҡ”')
      return
    }

    setLoading(true)

    try {
      const response = await api.post('/api/seller/register', {
        email: formData.email,
        password: formData.password,
        name: formData.name,
        phone: formData.phone,
        business_number: formData.businessNumber,
        company_name: formData.companyName
      })

      if (response.data.success) {
        alert('нҡҢмӣҗк°Җмһ…мқҙ мҷ„лЈҢлҗҳм—ҲмҠөлӢҲлӢӨ!\nкҙҖлҰ¬мһҗ мҠ№мқё нӣ„ лЎңк·ёмқён•  мҲҳ мһҲмҠөлӢҲлӢӨ.')
        navigate('/seller/login')
      } else {
        setError(response.data.error || 'нҡҢмӣҗк°Җмһ… мӢӨнҢЁ')
      }
    } catch (err: any) {
      setError(err.response?.data?.error || err.response?.data?.message || 'нҡҢмӣҗк°Җмһ… мӢӨнҢЁ')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-purple-50 to-pink-100 flex items-center justify-center px-4 py-12">
      <div className="max-w-2xl w-full">
        {/* Logo */}
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-gray-900 mb-2">рҹ‘ЁвҖҚрҹ’ј</h1>
          <h2 className="text-3xl font-bold text-gray-900">м…Җлҹ¬ нҡҢмӣҗк°Җмһ…</h2>
          <p className="text-gray-600 mt-2">лҰ¬мҠӨн„°мҪ”нҚјл Ҳмқҙм…ҳ нҢҗл§Өмһҗ л“ұлЎқ</p>
        </div>

        {/* Registration Form */}
        <div className="bg-white rounded-2xl shadow-xl p-8">
          <form onSubmit={handleSubmit} className="space-y-6">
            {error && (
              <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg">
                {error}
              </div>
            )}

            {/* кё°ліё м •ліҙ */}
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-gray-900">кё°ліё м •ліҙ</h3>
              
              <div>
                <label htmlFor="email" className="block text-sm font-medium text-gray-700 mb-2">
                  мқҙл©”мқј *
                </label>
                <input
                  id="email"
                  name="email"
                  type="email"
                  value={formData.email}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  placeholder="seller@example.com"
                />
              </div>

              <div>
                <label htmlFor="password" className="block text-sm font-medium text-gray-700 mb-2">
                  л№„л°ҖлІҲнҳё * (6мһҗ мқҙмғҒ)
                </label>
                <input
                  id="password"
                  name="password"
                  type="password"
                  value={formData.password}
                  onChange={handleChange}
                  required
                  minLength={6}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  placeholder="вҖўвҖўвҖўвҖўвҖўвҖўвҖўвҖў"
                />
              </div>

              <div>
                <label htmlFor="passwordConfirm" className="block text-sm font-medium text-gray-700 mb-2">
                  л№„л°ҖлІҲнҳё нҷ•мқё *
                </label>
                <input
                  id="passwordConfirm"
                  name="passwordConfirm"
                  type="password"
                  value={formData.passwordConfirm}
                  onChange={handleChange}
                  required
                  minLength={6}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  placeholder="вҖўвҖўвҖўвҖўвҖўвҖўвҖўвҖў"
                />
              </div>

              <div>
                <label htmlFor="name" className="block text-sm font-medium text-gray-700 mb-2">
                  мқҙлҰ„ *
                </label>
                <input
                  id="name"
                  name="name"
                  type="text"
                  value={formData.name}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  placeholder="нҷҚкёёлҸҷ"
                />
              </div>

              <div>
                <label htmlFor="phone" className="block text-sm font-medium text-gray-700 mb-2">
                  м „нҷ”лІҲнҳё *
                </label>
                <input
                  id="phone"
                  name="phone"
                  type="tel"
                  value={formData.phone}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  placeholder="010-1234-5678"
                />
              </div>
            </div>

            {/* мӮ¬м—…мһҗ м •ліҙ */}
            <div className="space-y-4 pt-6 border-t border-gray-200">
              <h3 className="text-lg font-semibold text-gray-900">мӮ¬м—…мһҗ м •ліҙ</h3>
              
              <div>
                <label htmlFor="companyName" className="block text-sm font-medium text-gray-700 mb-2">
                  нҡҢмӮ¬лӘ… *
                </label>
                <input
                  id="companyName"
                  name="companyName"
                  type="text"
                  value={formData.companyName}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  placeholder="(мЈј)лҰ¬мҠӨн„°мҪ”нҚјл Ҳмқҙм…ҳ"
                />
              </div>

              <div>
                <label htmlFor="businessNumber" className="block text-sm font-medium text-gray-700 mb-2">
                  мӮ¬м—…мһҗл“ұлЎқлІҲнҳё *
                </label>
                <input
                  id="businessNumber"
                  name="businessNumber"
                  type="text"
                  value={formData.businessNumber}
                  onChange={handleChange}
                  required
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  placeholder="123-45-67890"
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-gradient-to-r from-purple-600 to-pink-600 text-white py-4 rounded-lg font-semibold hover:from-purple-700 hover:to-pink-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? 'к°Җмһ… мӨ‘...' : 'нҡҢмӣҗк°Җмһ…'}
            </button>
          </form>

          {/* Login Link */}
          <div className="mt-6 text-center">
            <p className="text-gray-600">
              мқҙлҜё кі„м •мқҙ мһҲмңјмӢ к°Җмҡ”?{' '}
              <button
                onClick={() => navigate('/seller/login')}
                className="text-purple-600 hover:text-purple-700 font-semibold"
              >
                лЎңк·ёмқён•ҳкё°
              </button>
            </p>
          </div>

          {/* Note */}
          <div className="mt-6 p-4 bg-blue-50 rounded-lg">
            <p className="text-xs text-blue-700">
              рҹ’Ў нҡҢмӣҗк°Җмһ… нӣ„ кҙҖлҰ¬мһҗ мҠ№мқёмқҙ н•„мҡ”н•©лӢҲлӢӨ. мҠ№мқёк№Ңм§Җ 1-2мқј мҶҢмҡ”лҗ  мҲҳ мһҲмҠөлӢҲлӢӨ.
            </p>
          </div>
        </div>

        {/* Back to Home */}
        <div className="text-center mt-6">
          <button
            onClick={() => navigate('/')}
            className="text-gray-600 hover:text-gray-900 text-sm"
          >
            вҶҗ нҷҲмңјлЎң лҸҢм•„к°Җкё°
          </button>
        </div>
      </div>
    </div>
  )
}
